import Foundation

struct CategoryContent2 {
    static let howAILearns = CategoryData(
        id: "how_ai_learns", name: "How AI Learns", icon: "graduationcap", colorName: "aiPurple",
        description: "Find out how machines learn from examples and data",
        lessons: [lesson1, lesson2, lesson3, lesson4, lesson5, lesson6], order: 1,
        unlockRequirement: .completeCategory("ai_basics")
    )

    static let lesson1 = LessonData(id: "hal_l1", title: "Supervised Learning", description: "Learning from labeled examples", categoryId: "how_ai_learns", questions: [
        Question(id: "hal1_q1", type: .multipleChoice, questionText: "In supervised learning, the model learns from:", options: ["Labeled data with known answers", "Reward signals from an environment", "Patterns discovered in unlabeled data", "Pre-programmed decision trees"], correctAnswer: "Labeled data with known answers", explanation: "Supervised learning uses datasets where each example has a correct answer (label) so the model can learn the mapping between inputs and outputs."),
        Question(id: "hal1_q2", type: .trueFalse, questionText: "Email spam detection is an example of supervised learning.", options: ["True", "False"], correctAnswer: "True", explanation: "Spam filters are trained on emails labeled as 'spam' or 'not spam' — a classic supervised learning task used by Gmail, Outlook, and virtually every email provider."),
        Question(id: "hal1_q3", type: .matchPairs, questionText: "Match supervised learning tasks:", matchPairs: [
            MatchPair(term: "Classification", definition: "Sorting into categories"),
            MatchPair(term: "Regression", definition: "Predicting a number"),
            MatchPair(term: "Label", definition: "The correct answer tag"),
            MatchPair(term: "Feature", definition: "Input variable for prediction")
        ], explanation: "Classification and regression are the two main types of supervised learning, used across industries from healthcare to finance."),
        Question(id: "hal1_q4", type: .fillInBlank, questionText: "In supervised learning, a __________ is the correct answer provided for each training example.", options: ["label", "feature", "node", "layer"], correctAnswer: "label", explanation: "Labels are the ground truth answers that the model learns to predict. Human annotators often create these labels, a process critical to training models at companies like Anthropic and Google DeepMind."),
        Question(id: "hal1_q5", type: .multipleChoice, questionText: "Which is a classification task?", options: ["Detecting if a medical scan shows a tumor or not", "Predicting tomorrow's temperature", "Grouping similar documents by topic", "Compressing a video file"], correctAnswer: "Detecting if a medical scan shows a tumor or not", explanation: "Classification assigns inputs to discrete categories — tumor vs. no tumor is a binary classification problem widely used in medical AI systems."),
        Question(id: "hal1_q6", type: .scenarioJudgment, questionText: "You want to predict house prices based on size, location, and age. Is supervised learning appropriate?", options: ["Yes, this is ideal", "No, not suitable", "It depends"], correctAnswer: "Yes, this is ideal", explanation: "Predicting house prices is a regression task, which is a core supervised learning application used by real estate platforms like Zillow and Redfin.")
    ], order: 0, difficulty: .beginner)

    static let lesson2 = LessonData(id: "hal_l2", title: "Unsupervised Learning", description: "Finding hidden patterns", categoryId: "how_ai_learns", questions: [
        Question(id: "hal2_q1", type: .multipleChoice, questionText: "Unsupervised learning works with:", options: ["Unlabeled data", "Data with known correct answers", "Reward-based feedback loops", "Manually defined categories"], correctAnswer: "Unlabeled data", explanation: "Unsupervised learning finds patterns in data without pre-existing labels or correct answers, making it valuable when labeled data is scarce or expensive to create."),
        Question(id: "hal2_q2", type: .trueFalse, questionText: "Clustering is a type of unsupervised learning.", options: ["True", "False"], correctAnswer: "True", explanation: "Clustering groups similar data points together without knowing the categories in advance. It is one of the most widely used unsupervised techniques."),
        Question(id: "hal2_q3", type: .multipleChoice, questionText: "Which is an example of unsupervised learning?", options: ["Grouping customers by shopping behavior", "Translating English to French", "Detecting spam emails", "Grading exam papers"], correctAnswer: "Grouping customers by shopping behavior", explanation: "Customer segmentation discovers natural groupings without predefined categories — a classic unsupervised learning task used by e-commerce and streaming platforms."),
        Question(id: "hal2_q4", type: .fillInBlank, questionText: "__________ is a technique that groups similar data points together without labels.", options: ["Clustering", "Classification", "Regression", "Tokenization"], correctAnswer: "Clustering", explanation: "Clustering algorithms like K-means group data points based on similarity, helping companies discover natural patterns in user behavior, genomic data, and more."),
        Question(id: "hal2_q5", type: .matchPairs, questionText: "Match unsupervised techniques:", matchPairs: [
            MatchPair(term: "Clustering", definition: "Group similar items together"),
            MatchPair(term: "Anomaly Detection", definition: "Find unusual data points"),
            MatchPair(term: "Dimensionality Reduction", definition: "Simplify complex data"),
            MatchPair(term: "Association", definition: "Find rules between items")
        ], explanation: "These techniques power fraud detection systems, recommendation engines, and scientific data analysis across the industry."),
        Question(id: "hal2_q6", type: .multipleChoice, questionText: "Why is unsupervised learning useful?", options: ["It can discover patterns humans haven't noticed", "It's always more accurate than supervised learning", "It never makes mistakes", "It doesn't need any data"], correctAnswer: "It can discover patterns humans haven't noticed", explanation: "Unsupervised learning can reveal hidden structures and relationships in data that humans might miss, which is why it is used in scientific research and business analytics.")
    ], order: 1, difficulty: .beginner)

    static let lesson3 = LessonData(id: "hal_l3", title: "Reinforcement Learning", description: "Learning through trial and error", categoryId: "how_ai_learns", questions: [
        Question(id: "hal3_q1", type: .multipleChoice, questionText: "Reinforcement learning is best described as:", options: ["Learning by trying actions and receiving rewards", "Learning from pre-labeled datasets", "Learning by finding clusters in data", "Learning by following pre-written rules"], correctAnswer: "Learning by trying actions and receiving rewards", explanation: "RL agents learn by taking actions in an environment and receiving reward or penalty signals, improving their strategy over time through trial and error."),
        Question(id: "hal3_q2", type: .trueFalse, questionText: "Google DeepMind's AlphaGo, which beat the world Go champion, used reinforcement learning.", options: ["True", "False"], correctAnswer: "True", explanation: "AlphaGo used reinforcement learning to play millions of games against itself and improve, becoming one of the most celebrated AI achievements in history."),
        Question(id: "hal3_q3", type: .fillInBlank, questionText: "In reinforcement learning, the AI receives a __________ signal to know if its action was good or bad.", options: ["reward", "label", "cluster", "feature"], correctAnswer: "reward", explanation: "Reward signals tell the agent whether its actions lead to good or bad outcomes. This same principle is used in RLHF (Reinforcement Learning from Human Feedback) to align models like Claude and GPT."),
        Question(id: "hal3_q4", type: .multipleChoice, questionText: "Which scenario best fits reinforcement learning?", options: ["Training a robot to navigate a warehouse", "Sorting emails into folders", "Grouping news articles by topic", "Converting speech to text"], correctAnswer: "Training a robot to navigate a warehouse", explanation: "A robot learning to navigate through trial and error, receiving rewards for reaching goals and penalties for collisions, is a classic RL application used in robotics and logistics."),
        Question(id: "hal3_q5", type: .matchPairs, questionText: "Match RL concepts:", matchPairs: [
            MatchPair(term: "Agent", definition: "The learner that takes actions"),
            MatchPair(term: "Environment", definition: "The world the agent acts in"),
            MatchPair(term: "Reward", definition: "Feedback signal for actions"),
            MatchPair(term: "Policy", definition: "Strategy for choosing actions")
        ], explanation: "These are the key components of any reinforcement learning system, from game-playing AIs to robotic control systems."),
        Question(id: "hal3_q6", type: .scenarioJudgment, questionText: "A game company wants AI to learn to play their new game without human demonstrations. Is RL a good choice?", options: ["Yes, this is ideal", "No, not suitable", "It depends"], correctAnswer: "Yes, this is ideal", explanation: "Reinforcement learning excels at learning game strategies through self-play. Google DeepMind's AlphaZero mastered chess, Go, and shogi this way without any human game data.")
    ], order: 2, difficulty: .intermediate)

    static let lesson4 = LessonData(id: "hal_l4", title: "Overfitting & Underfitting", description: "When models learn too much or too little", categoryId: "how_ai_learns", questions: [
        Question(id: "hal4_q1", type: .multipleChoice, questionText: "Overfitting means a model:", options: ["Memorizes training data but fails on new data", "Generalizes well across all datasets", "Is too simple to capture patterns", "Requires too much training data"], correctAnswer: "Memorizes training data but fails on new data", explanation: "An overfit model has essentially memorized the training data but cannot generalize to new, unseen data — a challenge that every AI lab must address during model development."),
        Question(id: "hal4_q2", type: .trueFalse, questionText: "A model that performs well on training data but poorly on test data is likely overfitting.", options: ["True", "False"], correctAnswer: "True", explanation: "This gap between training and test performance is the hallmark of overfitting, and monitoring it is a critical part of responsible model development."),
        Question(id: "hal4_q3", type: .fillInBlank, questionText: "__________ occurs when a model is too simple to capture the patterns in the data.", options: ["Underfitting", "Overfitting", "Clustering", "Labeling"], correctAnswer: "Underfitting", explanation: "Underfitting means the model has not learned enough from the data and performs poorly everywhere, often requiring a more capable architecture or more training."),
        Question(id: "hal4_q4", type: .multipleChoice, questionText: "Which technique helps prevent overfitting?", options: ["Using a validation set", "Increasing model complexity indefinitely", "Removing the test dataset entirely", "Training exclusively on the validation set"], correctAnswer: "Using a validation set", explanation: "A validation set lets you monitor the model's performance on unseen data during training to detect overfitting, a standard practice at organizations like Anthropic, Meta AI, and Mistral."),
        Question(id: "hal4_q5", type: .sortOrder, questionText: "Order these from underfitting to overfitting:", options: ["Good fit model", "Memorizing all training data", "Too simple model", "Slightly complex model"], correctAnswers: ["Too simple model", "Good fit model", "Slightly complex model", "Memorizing all training data"], explanation: "The goal is to find the sweet spot between underfitting and overfitting, achieving strong performance on new data."),
        Question(id: "hal4_q6", type: .multipleChoice, questionText: "What is the 'sweet spot' between underfitting and overfitting called?", options: ["Good generalization", "Perfect memory", "Data compression", "Feature extraction"], correctAnswer: "Good generalization", explanation: "A well-generalized model performs well on both training data and new, unseen data — the ultimate goal of model training across the AI industry.")
    ], order: 3, difficulty: .intermediate)

    static let lesson5 = LessonData(id: "hal_l5", title: "Model Evaluation", description: "How to measure AI performance", categoryId: "how_ai_learns", questions: [
        Question(id: "hal5_q1", type: .multipleChoice, questionText: "Accuracy in ML means:", options: ["Percentage of correct predictions", "How fast the model trains", "The number of features used", "The complexity of the model"], correctAnswer: "Percentage of correct predictions", explanation: "Accuracy measures how often the model's predictions match the actual correct answers. AI benchmarks like MMLU and HumanEval use various metrics to compare models from different labs."),
        Question(id: "hal5_q2", type: .trueFalse, questionText: "High accuracy always means a model is good.", options: ["True", "False"], correctAnswer: "False", explanation: "In imbalanced datasets, a model could predict the majority class every time and have high accuracy but be useless. This is why AI researchers use multiple evaluation metrics."),
        Question(id: "hal5_q3", type: .matchPairs, questionText: "Match evaluation metrics:", matchPairs: [
            MatchPair(term: "Precision", definition: "Of predicted positives, how many are correct"),
            MatchPair(term: "Recall", definition: "Of actual positives, how many were found"),
            MatchPair(term: "F1 Score", definition: "Balance of precision and recall"),
            MatchPair(term: "Accuracy", definition: "Overall correct predictions percentage")
        ], explanation: "Different metrics capture different aspects of model performance, which is why leaderboards comparing Claude, Gemini, GPT, and Llama use multiple benchmarks."),
        Question(id: "hal5_q4", type: .fillInBlank, questionText: "A __________ set is data held back from training to evaluate the model's performance.", options: ["test", "training", "bias", "weight"], correctAnswer: "test", explanation: "The test set is never used during training, ensuring a fair evaluation of the model. Contamination of test sets is a serious concern in AI benchmarking."),
        Question(id: "hal5_q5", type: .scenarioJudgment, questionText: "A cancer detection AI has 95% accuracy but misses 40% of actual cancer cases. Is this model good enough?", options: ["No, recall is too low", "Yes, 95% is great", "It depends"], correctAnswer: "No, recall is too low", explanation: "For medical diagnosis, recall (sensitivity) matters enormously — missing 40% of cancers could be life-threatening. This is why healthcare AI requires rigorous multi-metric evaluation."),
        Question(id: "hal5_q6", type: .multipleChoice, questionText: "What is cross-validation?", options: ["Testing the model on multiple different data splits", "Splitting data once into train and test", "Comparing results across different models", "Verifying data integrity before training"], correctAnswer: "Testing the model on multiple different data splits", explanation: "Cross-validation trains and tests on different subsets of data to get a more reliable performance estimate, reducing the chance that results are due to a lucky data split.")
    ], order: 4, difficulty: .intermediate)

    static let lesson6 = LessonData(id: "hal_l6", title: "Transfer Learning", description: "Building on existing knowledge", categoryId: "how_ai_learns", questions: [
        Question(id: "hal6_q1", type: .multipleChoice, questionText: "Transfer learning means:", options: ["Using knowledge from one task to help with another", "Training a model from scratch on new data", "Converting one model type to another", "Sharing training data between organizations"], correctAnswer: "Using knowledge from one task to help with another", explanation: "Transfer learning reuses a model trained on one task as the starting point for a different but related task, dramatically reducing the resources needed."),
        Question(id: "hal6_q2", type: .trueFalse, questionText: "Transfer learning can reduce the amount of training data needed for a new task.", options: ["True", "False"], correctAnswer: "True", explanation: "Since the model already learned general features, it needs less data to adapt to the new specific task. This is why fine-tuning pre-trained models is so popular."),
        Question(id: "hal6_q3", type: .fillInBlank, questionText: "In transfer learning, a model trained on a large dataset is __________ on a smaller, specific dataset.", options: ["fine-tuned", "retrained", "evaluated", "normalized"], correctAnswer: "fine-tuned", explanation: "Fine-tuning adjusts the pre-trained model's parameters slightly to adapt to the new task. Companies fine-tune base models from Meta AI (Llama), Mistral, and others for specialized applications."),
        Question(id: "hal6_q4", type: .multipleChoice, questionText: "Which is a good analogy for transfer learning?", options: ["A musician learning a new instrument faster", "Starting from scratch every time", "Forgetting everything you learned", "Using a calculator for math"], correctAnswer: "A musician learning a new instrument faster", explanation: "Just as musical skills transfer between instruments, learned features transfer between AI tasks, saving enormous amounts of time and compute."),
        Question(id: "hal6_q5", type: .scenarioJudgment, questionText: "You have limited medical images but want to build a diagnosis model. Should you use transfer learning from a model trained on millions of general images?", options: ["Yes, this is ideal", "No, not suitable", "It depends"], correctAnswer: "Yes, this is ideal", explanation: "Transfer learning is perfect here — the model already knows general image features and can be fine-tuned for medical images with a fraction of the data otherwise needed."),
        Question(id: "hal6_q6", type: .multipleChoice, questionText: "Which AI approach heavily relies on transfer learning?", options: ["Fine-tuning foundation models like Llama or Mistral", "K-means clustering algorithms", "Classical decision tree models", "Traditional database query systems"], correctAnswer: "Fine-tuning foundation models like Llama or Mistral", explanation: "Foundation models from Anthropic, Meta AI, Mistral, and others are pre-trained on massive data, then fine-tuned for specific tasks — the most prominent example of transfer learning today.")
    ], order: 5, difficulty: .advanced)
}
